#include <vector>
#include <queue>
#include <climits>
#include <tuple>

using namespace std;

long long solve(long long m, long long n, vector<vector<long long>> waitCost) {
    if (m == 0 || n == 0) return 0;

    // Directions: right (0, 1), down (1, 0)
    vector<pair<int, int>> dirs = {{0, 1}, {1, 0}};

    // Priority queue: (total_cost, step, i, j)
    priority_queue<tuple<long long, long long, long long, long long>, 
                   vector<tuple<long long, long long, long long, long long>>, 
                   greater<tuple<long long, long long, long long, long long>>> pq;

    // Cost matrix: step % 2, i, j -> cost
    vector<vector<vector<long long>>> cost(2, vector<vector<long long>>(m, vector<long long>(n, LLONG_MAX)));

    // Initial position (0, 0) at step 1
    long long initial_cost = (0 + 1) * (0 + 1);
    pq.push({initial_cost, 1, 0, 0});
    cost[1 % 2][0][0] = initial_cost;

    while (!pq.empty()) {
        auto [current_cost, step, i, j] = pq.top();
        pq.pop();

        if (i == m - 1 && j == n - 1) {
            return current_cost;
        }

        if (step % 2 == 1) { // Odd step: move right or down
            for (auto [di, dj] : dirs) {
                long long ni = i + di;
                long long nj = j + dj;
                if (ni < m && nj < n) {
                    long long move_cost = (ni + 1) * (nj + 1);
                    long long new_cost = current_cost + move_cost;
                    long long new_step = step + 1;
                    if (new_cost < cost[new_step % 2][ni][nj]) {
                        cost[new_step % 2][ni][nj] = new_cost;
                        pq.push({new_cost, new_step, ni, nj});
                    }
                }
            }
        } else { // Even step: wait
            long long wait_cost = waitCost[i][j];
            long long new_cost = current_cost + wait_cost;
            long long new_step = step + 1;
            if (new_cost < cost[new_step % 2][i][j]) {
                cost[new_step % 2][i][j] = new_cost;
                pq.push({new_cost, new_step, i, j});
            }
        }
    }

    return -1; // unreachable
}

